function TaskDialog()
this:AddTalk("<p><n color=\"255,0,255,0\">温馨提示：</n></p>");
this:AddTalk("<p><n color=\"255,0,255,255\">神魔之隙内涵城主，玩家可攻城，总舵内另外开放神魔之隙内阁，里面也刷新有1只极品BOSS。</n></p>");
